-- PostgreSQL Schema for Drivemarket
CREATE TABLE usuarios (id SERIAL PRIMARY KEY, nombre VARCHAR(100) NOT NULL, apellidos VARCHAR(100), telefono VARCHAR(20), username VARCHAR(50) NOT NULL UNIQUE, email VARCHAR(100) NOT NULL UNIQUE, password VARCHAR(255), foto VARCHAR(255), fecha_registro TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, rol VARCHAR(20) NOT NULL DEFAULT 'comprador' CHECK (rol IN ('comprador','vendedor','admin','superadmin','editor','moderador')), estado VARCHAR(20) NOT NULL DEFAULT 'activo' CHECK (estado IN ('activo','inactivo','bloqueado')), ultima_sesion TIMESTAMP, nombre_empresa VARCHAR(200));
CREATE TABLE tipos_vehiculos (id SERIAL PRIMARY KEY, nombre VARCHAR(50) NOT NULL);
CREATE TABLE marcas (id SERIAL PRIMARY KEY, nombre VARCHAR(100) NOT NULL, logo VARCHAR(255));
CREATE TABLE modelos (id SERIAL PRIMARY KEY, id_marca INT NOT NULL REFERENCES marcas(id) ON DELETE CASCADE, nombre VARCHAR(100) NOT NULL);
CREATE TABLE colores (id SERIAL PRIMARY KEY, nombre VARCHAR(50) NOT NULL);
CREATE TABLE caracteristicas (id SERIAL PRIMARY KEY, nombre VARCHAR(100) NOT NULL);
CREATE TABLE vehiculos (id SERIAL PRIMARY KEY, id_usuario INT REFERENCES usuarios(id) ON DELETE SET NULL, id_tipo INT REFERENCES tipos_vehiculos(id) ON DELETE SET NULL, id_marca INT REFERENCES marcas(id) ON DELETE SET NULL, id_modelo INT REFERENCES modelos(id) ON DELETE SET NULL, version VARCHAR(100), id_color INT REFERENCES colores(id) ON DELETE SET NULL, anio INT, placa VARCHAR(10), ciudad_placa VARCHAR(100), ciudad_venta VARCHAR(100), dueno VARCHAR(10) DEFAULT 'Si', kilometraje INT, precio NUMERIC(12,2), negociable VARCHAR(10) DEFAULT 'No', imagen VARCHAR(255), fecha_publicacion TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, estado VARCHAR(20) DEFAULT 'activo', usuario_id INT REFERENCES usuarios(id) ON DELETE SET NULL, vistas INT DEFAULT 0, destacado BOOLEAN DEFAULT FALSE, slug VARCHAR(255) UNIQUE, descripcion TEXT);
CREATE TABLE imagenes_vehiculos (id SERIAL PRIMARY KEY, id_vehiculo INT NOT NULL REFERENCES vehiculos(id) ON DELETE CASCADE, url_imagen VARCHAR(255) NOT NULL);
CREATE TABLE vehiculo_caracteristicas (id SERIAL PRIMARY KEY, id_vehiculo INT NOT NULL REFERENCES vehiculos(id) ON DELETE CASCADE, id_caracteristica INT NOT NULL REFERENCES caracteristicas(id) ON DELETE CASCADE);
CREATE TABLE favoritos (id SERIAL PRIMARY KEY, id_usuario INT NOT NULL REFERENCES usuarios(id) ON DELETE CASCADE, id_vehiculo INT NOT NULL REFERENCES vehiculos(id) ON DELETE CASCADE, fecha_agregado TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE conversaciones (id SERIAL PRIMARY KEY, id_vehiculo INT NOT NULL REFERENCES vehiculos(id) ON DELETE CASCADE, id_comprador INT NOT NULL REFERENCES usuarios(id) ON DELETE CASCADE, id_vendedor INT NOT NULL REFERENCES usuarios(id) ON DELETE CASCADE, fecha_creacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP, ultima_actividad TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE (id_vehiculo, id_comprador, id_vendedor));
CREATE TABLE mensajes (id SERIAL PRIMARY KEY, id_conversacion INT NOT NULL REFERENCES conversaciones(id) ON DELETE CASCADE, id_remitente INT NOT NULL REFERENCES usuarios(id) ON DELETE CASCADE, contenido TEXT NOT NULL, fecha_envio TIMESTAMP DEFAULT CURRENT_TIMESTAMP, leido BOOLEAN DEFAULT FALSE);
CREATE TABLE alertas_precio (id SERIAL PRIMARY KEY, id_usuario INT NOT NULL REFERENCES usuarios(id) ON DELETE CASCADE, id_vehiculo INT NOT NULL REFERENCES vehiculos(id) ON DELETE CASCADE, precio_referencia NUMERIC(12,2) NOT NULL, fecha_creacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP, notificado BOOLEAN DEFAULT FALSE, fecha_notificacion TIMESTAMP, UNIQUE (id_usuario, id_vehiculo));
CREATE TABLE notificaciones (id SERIAL PRIMARY KEY, id_usuario INT NOT NULL REFERENCES usuarios(id) ON DELETE CASCADE, tipo VARCHAR(50) NOT NULL, titulo VARCHAR(100) NOT NULL, mensaje TEXT NOT NULL, url_accion VARCHAR(255), id_relacion INT, leida BOOLEAN DEFAULT FALSE, fecha_creacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP, fecha_leida TIMESTAMP);
CREATE TABLE perfil_vendedor (id SERIAL PRIMARY KEY, usuario_id INT NOT NULL UNIQUE REFERENCES usuarios(id) ON DELETE CASCADE, nombre_tienda VARCHAR(100) NOT NULL, email_comercial VARCHAR(100) NOT NULL, numero_id VARCHAR(50) NOT NULL, descripcion TEXT, telefono_contacto VARCHAR(20), direccion_negocio VARCHAR(255), banco VARCHAR(50), numero_cuenta VARCHAR(50), foto_id_frontal VARCHAR(255), foto_id_trasera VARCHAR(255), foto_portada VARCHAR(255), logo_tienda VARCHAR(255), estado_verificacion VARCHAR(20) DEFAULT 'pendiente' CHECK (estado_verificacion IN ('pendiente','aprobado','rechazado')));
CREATE TABLE reportes (id SERIAL PRIMARY KEY, id_usuario INT NOT NULL REFERENCES usuarios(id) ON DELETE CASCADE, id_vehiculo INT REFERENCES vehiculos(id) ON DELETE SET NULL, id_reportador INT, id_reportado INT, titulo VARCHAR(255), motivo VARCHAR(255), detalle TEXT, descripcion TEXT, estado VARCHAR(20) DEFAULT 'pendiente', fecha TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, fecha_reporte TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE resenas (id SERIAL PRIMARY KEY, id_autor INT NOT NULL REFERENCES usuarios(id), id_calificado INT NOT NULL REFERENCES usuarios(id), estrellas INT NOT NULL, comentario TEXT, fecha TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE logs_recuperacion (id SERIAL PRIMARY KEY, email VARCHAR(100), codigo VARCHAR(20), fecha_envio TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE soporte_chats (id SERIAL PRIMARY KEY, id_usuario INT NOT NULL REFERENCES usuarios(id) ON DELETE CASCADE, asunto VARCHAR(150), estado VARCHAR(20) DEFAULT 'abierto' CHECK (estado IN ('abierto','cerrado')), fecha_creacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE soporte_mensajes (id SERIAL PRIMARY KEY, id_chat INT NOT NULL REFERENCES soporte_chats(id) ON DELETE CASCADE, id_remitente INT NOT NULL, mensaje TEXT NOT NULL, es_admin BOOLEAN DEFAULT FALSE, fecha TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE tipo_marca (id SERIAL PRIMARY KEY, id_tipo INT NOT NULL REFERENCES tipos_vehiculos(id) ON DELETE CASCADE, id_marca INT NOT NULL REFERENCES marcas(id) ON DELETE CASCADE, UNIQUE (id_tipo, id_marca));
CREATE TABLE faqs (id SERIAL PRIMARY KEY, pregunta VARCHAR(500) NOT NULL, respuesta TEXT NOT NULL, categoria VARCHAR(100) DEFAULT 'general', orden INT DEFAULT 0, activo BOOLEAN DEFAULT TRUE, creado_por INT REFERENCES usuarios(id) ON DELETE SET NULL, fecha_creacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE conversaciones_chatbot (id SERIAL PRIMARY KEY, usuario_id INT REFERENCES usuarios(id) ON DELETE SET NULL, session_id VARCHAR(100) NOT NULL, pregunta TEXT NOT NULL, respuesta TEXT NOT NULL, tipo_respuesta VARCHAR(20) DEFAULT 'faq', feedback BOOLEAN, fecha TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE promociones (id SERIAL PRIMARY KEY, titulo VARCHAR(150) NOT NULL, descripcion TEXT, etiqueta VARCHAR(50), color_etiqueta VARCHAR(30) DEFAULT 'var(--orange)', texto_boton VARCHAR(50) DEFAULT 'Ver mas', enlace_boton VARCHAR(255) DEFAULT '#', imagen VARCHAR(255) NOT NULL, activa BOOLEAN DEFAULT TRUE, orden INT DEFAULT 0, fecha_creacion TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE logs_admin (id SERIAL PRIMARY KEY, id_admin INT, nombre_admin VARCHAR(200), accion VARCHAR(100) NOT NULL, entidad VARCHAR(50), id_entidad INT, descripcion TEXT, ip VARCHAR(50), fecha TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE preferencias_usuario (id SERIAL PRIMARY KEY, usuario_id INT NOT NULL UNIQUE REFERENCES usuarios(id) ON DELETE CASCADE, notif_mensajes BOOLEAN DEFAULT TRUE, notif_ofertas BOOLEAN DEFAULT TRUE, notif_favoritos BOOLEAN DEFAULT TRUE, notif_updates BOOLEAN DEFAULT TRUE, notif_nuevas_pub BOOLEAN DEFAULT TRUE, notif_precio BOOLEAN DEFAULT TRUE, dos_fa_activo BOOLEAN DEFAULT FALSE, alerta_nuevo_login BOOLEAN DEFAULT FALSE, visibilidad VARCHAR(20) DEFAULT 'publico', mostrar_telefono BOOLEAN DEFAULT TRUE, en_busquedas BOOLEAN DEFAULT TRUE, google_connected BOOLEAN DEFAULT FALSE);
CREATE TABLE historial_sesiones (id SERIAL PRIMARY KEY, usuario_id INT NOT NULL REFERENCES usuarios(id) ON DELETE CASCADE, ip VARCHAR(50), dispositivo VARCHAR(50), navegador VARCHAR(150), fecha TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
